query:
-- Fix category slugs with spaces
UPDATE categories SET slug = REPLACE(slug, ' ', '-') WHERE slug LIKE '% %';
-- Show updated slugs
SELECT id, name, slug FROM categories WHERE slug LIKE '%-%' ORDER BY id;

